-- 기존 계정 전부 삭제
DELETE FROM accounts;

-- trader_id NULL 허용
ALTER TABLE accounts ALTER COLUMN trader_id DROP NOT NULL;

-- 전체 21개 계정 일괄 INSERT

-- RLS 읽기 정책 추가 (모든 인증 사용자가 계정 조회 가능)
DROP POLICY IF EXISTS "all_authenticated_read_accounts" ON accounts;
CREATE POLICY "all_authenticated_read_accounts" ON accounts
  FOR SELECT USING (auth.uid() IS NOT NULL);
